<table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:14px;"><thead><tr style="background:#1e3a5f;color:#fff;"><th style="padding:10px;text-align:left;">Category</th><th style="padding:10px;">Price (AED)</th></tr></thead><tbody>
<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Adult — Standard</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>100–120</strong></td></tr>
<tr><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Child (3–12)</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>75–90</strong></td></tr>
<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Sunset Slot</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>+20–30 premium</strong></td></tr>
<tr><td style="padding:10px;">Under 3</td><td style="padding:10px;"><strong>Free</strong></td></tr>
</tbody></table>
