<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Observatory Only — Adult</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>65–85</strong></td></tr>
<tr><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Observatory + Glass Slide</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>110–140</strong></td></tr>
<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Edge Walk Add-On</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>+150–200</strong></td></tr>
