<table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:14px;"><thead><tr style="background:#1e3a5f;color:#fff;"><th style="padding:10px;text-align:left;">Day</th><th style="padding:10px;">Hours</th></tr></thead><tbody>
<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Sunday – Thursday</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">10:00 AM – 10:00 PM</td></tr>
